    32→import org.semanticweb.owlapi.model.OWLObjectComplementOf;
    33→import org.semanticweb.owlapi.model.OWLObjectExactCardinality;
    34→import org.semanticweb.owlapi.model.OWLObjectHasValue;
    35→import org.semanticweb.owlapi.model.OWLObjectIntersectionOf;
    36→import org.semanticweb.owlapi.model.OWLObjectMaxCardinality;
    37→import org.semanticweb.owlapi.model.OWLObjectMinCardinality;
    38→import org.semanticweb.owlapi.model.OWLObjectOneOf;
    39→import org.semanticweb.owlapi.model.OWLObjectProperty;
    40→import org.semanticweb.owlapi.model.OWLObjectSomeValuesFrom;
    41→import org.semanticweb.owlapi.model.OWLObjectUnionOf;
    42→import org.semanticweb.owlapi.model.OWLObjectVisitor;
    43→import org.semanticweb.owlapi.model.OWLOntology;
    44→import org.semanticweb.owlapi.model.OWLSubClassOfAxiom;
