    46→/**
    47→ * Visitor interface to inspect OWL Class Restrictions.
    48→ *
    49→ * <p>This visitor traverses an OWL class hierarchy and collects type-safe restriction information
    50→ * for both object properties and data properties. It implements the Visitor pattern via
    51→ * {@link OWLObjectVisitor} to handle different types of OWL class expressions.
    52→ *
    53→ * <h2>Usage</h2>
    54→ * <pre>{@code
    55→ * OWLClass myClass = ...;
    56→ * OWLOntology ontology = ...;
    57→ * OWLClass owlThing = dataFactory.getOWLThing();
    58→ *
    59→ * SchemaVisitor visitor = new SchemaVisitor(myClass, ontology, owlThing);
    60→ * myClass.accept(visitor);
    61→ *
    62→ * // Access collected restrictions
    63→ * Map<String, List<RestrictionInfo>> restrictions = visitor.getRestrictions();
    64→ * Set<String> objectProperties = visitor.getObjectPropertyNames();
    65→ * }</pre>
    66→ *
    67→ * <h2>Constructor Parameters</h2>
    68→ * <ul>
    69→ *   <li><b>visitedClass</b>: The OWL class to analyze for restrictions</li>
    70→ *   <li><b>onto</b>: The ontology containing the class and its axioms</li>
    71→ *   <li><b>owlThing</b>: Reference to owl:Thing for filtering (restrictions to owl:Thing are ignored)</li>
    72→ * </ul>
    73→ *
    74→ * <h2>Visitor Traversal Behavior</h2>
    75→ * <p>The visitor recursively processes class hierarchies:
    76→ * <ul>
    77→ *   <li>When visiting a class, all {@link org.semanticweb.owlapi.model.OWLSubClassOfAxiom}s are followed</li>
    78→ *   <li>Cycle detection via {@code processedClasses} prevents infinite recursion in circular hierarchies</li>
    79→ *   <li>Complex class expressions (unions, intersections) are recursively traversed via {@code accept()}</li>
    80→ *   <li>Property restrictions are collected and stored as type-safe {@link RestrictionInfo} objects</li>
    81→ * </ul>
    82→ *
    83→ * <h2>Thread Safety</h2>
    84→ * <p>This class is <b>not thread-safe</b>. Each visitor instance maintains mutable state during
    85→ * traversal and should not be shared between threads or reused for multiple traversals.
    86→ *
    87→ * @see RestrictionInfo
    88→ * @see PropertyNameResolver
    89→ */
    90→public class SchemaVisitor implements OWLObjectVisitor {
    91→
    92→  private static final Logger logger = Logger.getLogger(SchemaVisitor.class.getName());
    93→
    94→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
    95→  private final TaxonomyPatternDetector taxonomyDetector;
    96→  private final Set<OWLClass> processedClasses;
    97→  private final OWLClass cls;
    98→  private final OWLOntology onto;
    99→  private final OWLClass owlThing;
   100→  private String propertyName;
   101→
   102→
   103→  // Type-safe storage (private with unmodifiable getters)
   104→  private final Map<String, Set<RestrictionInfo>> restrictions = new HashMap<>();
   105→  private final Multimap<String, OWLClass> objectPropertyRanges = HashMultimap.create();
   106→  private final Multimap<String, OWLDatatype> dataPropertyRanges = HashMultimap.create();
   107→
   108→  // Property name tracking (minimal - just names, not full OWL objects)
   109→  private final Set<String> objectPropertyNames = new HashSet<>();
   110→  private final Set<String> dataPropertyNames = new HashSet<>();
   111→
   112→  // Taxonomy pattern tracking
   113→  private final Map<String, TaxonomyInfo> taxonomyPatterns = new HashMap<>();
   114→
   115→  /**
   116→   * Creates a new SchemaVisitor to analyze OWL class restrictions.
   117→   *
   118→   * @param visitedClass the OWL class to analyze for restrictions
   119→   * @param onto         the ontology containing the class and its axioms
   120→   * @param owlThing     reference to owl:Thing (restrictions to owl:Thing are ignored as they add
   121→   *                     no information)
   122→   */
   123→  public SchemaVisitor(OWLClass visitedClass, OWLOntology onto, OWLClass owlThing) {
   124→    processedClasses = new HashSet<>();
   125→    this.cls = visitedClass;
   126→    this.onto = onto;
   127→    this.propertyName = "";
   128→    this.owlThing = owlThing;
   129→    this.taxonomyDetector = new TaxonomyPatternDetector(onto, nameResolver);
   130→  }
   131→
   132→  @Override
   133→  public void visit(OWLClass ce) {
   134→    if (!processedClasses.contains(ce)) {
   135→      processedClasses.add(ce);
   136→      for (OWLSubClassOfAxiom ax : onto.getSubClassAxiomsForSubClass(ce)) {
   137→        ax.getSuperClass().accept(this);
   138→      }
   139→    }
   140→  }
   141→
   142→  @Override
   143→  public void visit(OWLObjectSomeValuesFrom ce) {
   144→    handleObjectValuesFrom(ce, ce.getFiller(), new RestrictionInfo.SomeValuesFrom(ce));
   145→  }
   146→
   147→  @Override
   148→  public void visit(OWLObjectAllValuesFrom ce) {
   149→    handleObjectValuesFrom(ce, ce.getFiller(), new RestrictionInfo.AllValuesFrom(ce));
   150→  }
   151→
   152→  private void handleObjectValuesFrom(OWLClassExpression ce,
   153→      OWLClassExpression filler, RestrictionInfo info) {
   154→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   155→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   156→      propertyName = nameResolver.resolve(property);
   157→      objectPropertyNames.add(propertyName);
   158→      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>()).add(info);
   159→
   160→      // Detect taxonomy patterns
   161→      taxonomyDetector.detect(propertyName, filler)
   162→          .ifPresent(ti -> taxonomyPatterns.put(propertyName, ti));
   163→    }
   164→
   165→    if (filler instanceof OWLObjectUnionOf
   166→        || filler instanceof OWLObjectIntersectionOf
   167→        || filler instanceof OWLObjectOneOf) {
   168→      filler.accept(this);
   169→    } else {
   170→      if (!filler.asOWLClass().equals(owlThing)) {
   171→        objectPropertyRanges.put(propertyName, filler.asOWLClass());
   172→      } else {
   173→        logger.fine("Ignoring owl:Thing range " + propertyName);
   174→      }
   175→    }
   176→    propertyName = "";
   177→  }
   178→
   179→  @Override
   180→  public void visit(OWLObjectUnionOf ce) {
   181→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   182→    setBooleanCombinationObjectProperties(ce, ce.getOperands(),
   183→        ce.getObjectPropertiesInSignature());
   184→  }
   185→
   186→  @Override
   187→  public void visit(OWLObjectIntersectionOf ce) {
   188→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   189→    setBooleanCombinationObjectProperties(ce, ce.getOperands(),
   190→        ce.getObjectPropertiesInSignature());
   191→  }
   192→
   193→  @Override
   194→  public void visit(OWLObjectMinCardinality ce) {
   195→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   196→    setPropertiesWithCardinality(ce);
   197→  }
   198→
   199→  @Override
   200→  public void visit(OWLObjectMaxCardinality ce) {
   201→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   202→    setPropertiesWithCardinality(ce);
   203→  }
   204→
   205→  @Override
   206→  public void visit(OWLObjectExactCardinality ce) {
   207→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   208→    setPropertiesWithCardinality(ce);
   209→  }
   210→
   211→  @Override
   212→  public void visit(OWLObjectComplementOf ce) {
   213→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   214→    if (!propertyName.isEmpty()) {
   215→      ce.getOperand().accept(this);
   216→    }
   217→  }
   218→
   219→  @Override
   220→  public void visit(OWLObjectHasValue ce) {
   221→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   222→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   223→      propertyName = nameResolver.resolve(property);
   224→      objectPropertyNames.add(propertyName);
   225→    }
   226→    propertyName = "";
   227→  }
   228→
   229→  @Override
   230→  public void visit(OWLObjectOneOf ce) {
   231→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   232→    propertyName = "";
   233→  }
   234→
   235→  @Override
   236→  public void visit(OWLDataAllValuesFrom ce) {
   237→    handleDataValuesFrom(ce, ce.getFiller(), new RestrictionInfo.DataAllValuesFrom(ce));
   238→  }
   239→
   240→  @Override
   241→  public void visit(OWLDataSomeValuesFrom ce) {
   242→    handleDataValuesFrom(ce, ce.getFiller(), new RestrictionInfo.DataSomeValuesFrom(ce));
   243→  }
   244→
   245→  private void handleDataValuesFrom(OWLClassExpression ce,
   246→      OWLDataRange filler, RestrictionInfo info) {
   247→    logger.fine("Analyzed Class: " + this.cls + " with axiom: " + ce);
   248→    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
   249→      propertyName = nameResolver.resolve(property);
   250→      dataPropertyNames.add(propertyName);
   251→      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>()).add(info);
   252→    }
   253→
   254→    if (filler instanceof OWLDataUnionOf
   255→        || filler instanceof OWLDataIntersectionOf) {
   256→      filler.accept(this);
   257→    } else {
   258→      if (!filler.asOWLDatatype().equals(owlThing)) {
   259→        dataPropertyRanges.put(propertyName, filler.asOWLDatatype());
   260→      } else {
   261→        logger.fine("Ignoring owl:Thing range " + propertyName);
   262→      }
   263→    }
   264→    propertyName = "";
   265→  }
   266→
   267→  @Override
   268→  public void visit(OWLDataUnionOf ce) {
   269→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   270→    setBooleanCombinationDataProperties(ce, ce.getOperands(), ce.getDataPropertiesInSignature());
   271→  }
   272→
   273→  @Override
   274→  public void visit(OWLDataIntersectionOf ce) {
   275→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   276→    setBooleanCombinationDataProperties(ce, ce.getOperands(), ce.getDataPropertiesInSignature());
   277→  }
   278→
   279→  @Override
   280→  public void visit(OWLDataMinCardinality ce) {
   281→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   282→    setDataPropertiesWithCardinality(ce);
   283→  }
   284→
   285→  @Override
   286→  public void visit(OWLDataMaxCardinality ce) {
   287→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   288→    setDataPropertiesWithCardinality(ce);
   289→  }
   290→
   291→  @Override
   292→  public void visit(OWLDataExactCardinality ce) {
   293→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   294→    setDataPropertiesWithCardinality(ce);
   295→  }
   296→
   297→  @Override
   298→  public void visit(OWLDataOneOf ce) {
   299→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   300→    for (OWLLiteral value : ce.getValues()) {
   301→      // Values are now accessed via DataOneOf.getEnumValues() in mappers
   302→    }
   303→    propertyName = "";
   304→  }
   305→
   306→  @Override
   307→  public void visit(OWLDataComplementOf ce) {
   308→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   309→    propertyName = "";
   310→  }
   311→
   312→  @Override
   313→  public void visit(OWLDataHasValue ce) {
   314→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   315→    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
   316→      propertyName = nameResolver.resolve(property);
   317→      dataPropertyNames.add(propertyName);
   318→    }
   319→    propertyName = "";
   320→  }
   321→
   322→  private void setPropertiesWithCardinality(OWLObjectCardinalityRestriction ce) {
   323→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   324→      propertyName = nameResolver.resolve(property);
   325→      objectPropertyNames.add(propertyName);
   326→
   327→      final String propName = propertyName;
   328→      RestrictionInfo.from(ce).ifPresent(info ->
   329→          restrictions.computeIfAbsent(propName, k -> new LinkedHashSet<>()).add(info));
   330→
   331→      // Detect taxonomy patterns
   332→      taxonomyDetector.detect(propertyName, ce.getFiller())
   333→          .ifPresent(info -> taxonomyPatterns.put(propertyName, info));
   334→
   335→      if (ce.getFiller().isOWLClass()) {
   336→        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
   337→      }
   338→    }
   339→    propertyName = "";
   340→  }
   341→
   342→  private void setBooleanCombinationObjectProperties(OWLClassExpression expression,
   343→      Set<OWLClassExpression> ranges,
   344→      Set<OWLObjectProperty> properties) {
   345→    if (propertyName.isEmpty()) {
   346→      for (OWLObjectProperty property : properties) {
   347→        propertyName = nameResolver.resolve(property);
   348→        objectPropertyNames.add(propertyName);
   349→        for (OWLClassExpression range : ranges) {
   350→          for (OWLObjectProperty rangeProp : range.getObjectPropertiesInSignature()) {
   351→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   352→              range.accept(this);
   353→            }
   354→          }
   355→        }
   356→      }
   357→
   358→      for (OWLDataProperty property : expression.getDataPropertiesInSignature()) {
   359→        propertyName = nameResolver.resolve(property);
   360→        dataPropertyNames.add(propertyName);
   361→        for (OWLClassExpression range : ranges) {
   362→          for (OWLDataProperty rangeProp : range.getDataPropertiesInSignature()) {
   363→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   364→              range.accept(this);
   365→            }
   366→          }
   367→        }
   368→      }
   369→    } else {
   370→      for (OWLClassExpression range : ranges) {
   371→        Set<OWLClass> rangeClasses = range.getClassesInSignature();
   372→        if (rangeClasses.size() != 1) {
   373→          range.accept(this);
   374→        } else if (!range.asOWLClass().equals(owlThing)) {
   375→          // Range is tracked in objectPropertyRanges via visitor methods
   376→        } else {
   377→          logger.fine("Ignoring owl:Thing range " + propertyName);
   378→        }
   379→      }
   380→    }
   381→    propertyName = "";
   382→  }
   383→
   384→  private void setBooleanCombinationDataProperties(OWLDataRange expression,
   385→      Set<OWLDataRange> ranges,
   386→      Set<OWLDataProperty> properties) {
   387→    if (propertyName.isEmpty()) {
   388→      for (OWLDataProperty property : properties) {
   389→        propertyName = nameResolver.resolve(property);
   390→        dataPropertyNames.add(propertyName);
   391→        for (OWLDataRange range : ranges) {
   392→          for (OWLDataProperty rangeProp : range.getDataPropertiesInSignature()) {
   393→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   394→              range.accept(this);
   395→            }
   396→          }
   397→        }
   398→      }
   399→
   400→      for (OWLObjectProperty property : expression.getObjectPropertiesInSignature()) {
   401→        propertyName = nameResolver.resolve(property);
   402→        objectPropertyNames.add(propertyName);
   403→        for (OWLDataRange range : ranges) {
   404→          for (OWLObjectProperty rangeProp : range.getObjectPropertiesInSignature()) {
   405→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   406→              range.accept(this);
   407→            }
   408→          }
   409→        }
   410→      }
   411→    } else {
   412→      for (OWLDataRange range : ranges) {
   413→        Set<OWLDatatype> rangeDatatypes = range.getDatatypesInSignature();
   414→        if (rangeDatatypes.size() != 1) {
   415→          range.accept(this);
   416→        } else if (!range.asOWLDatatype().asOWLClass().equals(owlThing)) {
   417→          // Range is tracked in dataPropertyRanges via visitor methods
   418→        } else {
   419→          logger.fine("Ignoring owl:Thing range " + propertyName);
   420→        }
   421→      }
   422→    }
   423→    propertyName = "";
   424→  }
   425→
   426→  private void setDataPropertiesWithCardinality(OWLDataCardinalityRestriction ce) {
   427→    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
   428→      propertyName = nameResolver.resolve(property);
   429→      dataPropertyNames.add(propertyName);
   430→
   431→      final String propName = propertyName;
   432→      RestrictionInfo.from(ce).ifPresent(info ->
   433→          restrictions.computeIfAbsent(propName, k -> new LinkedHashSet<>()).add(info));
   434→
   435→      for (OWLDatatype datatype : ce.getDatatypesInSignature()) {
   436→        dataPropertyRanges.put(propertyName, datatype);
   437→      }
   438→    }
   439→    propertyName = "";
   440→  }
   441→
   442→  // Getters for type-safe storage (unmodifiable views)
   443→  public Map<String, Set<RestrictionInfo>> getRestrictions() {
   444→    return Collections.unmodifiableMap(restrictions);
   445→  }
   446→
   447→  public Multimap<String, OWLClass> getObjectPropertyRanges() {
   448→    return Multimaps.unmodifiableMultimap(objectPropertyRanges);
   449→  }
   450→
   451→  public Multimap<String, OWLDatatype> getDataPropertyRanges() {
   452→    return Multimaps.unmodifiableMultimap(dataPropertyRanges);
   453→  }
   454→
   455→  public Set<String> getObjectPropertyNames() {
   456→    return Collections.unmodifiableSet(objectPropertyNames);
   457→  }
   458→
   459→  public Set<String> getDataPropertyNames() {
   460→    return Collections.unmodifiableSet(dataPropertyNames);
   461→  }
   462→
   463→  public Map<String, TaxonomyInfo> getTaxonomyPatterns() {
   464→    return Collections.unmodifiableMap(taxonomyPatterns);
   465→  }
   466→
   467→  public OWLOntology getOntology() {
   468→    return onto;
   469→  }
   470→
   471→}

