    70→public class OntologyMapper {
    71→
    72→  private final static Logger logger = Logger.getLogger(OntologyMapper.class.getName());
    73→  private static final String FLATTENED_FILENAME = "ontology-flat.owl";
    74→  private static final String MERGED_FILENAME = "ontology-merged.owl";
    75→  private static final Pattern OAUTH_SCOPE_PATTERN = Pattern.compile("^[\\x21\\x23-\\x5B\\x5D-\\x7E]+$"); // https://datatracker.ietf.org/doc/html/rfc6749#section-3.3
    76→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
    77→  private final YamlConfig config;
    78→  private final OWLOntologyManager manager;
    79→  private final OWLOntology ontology;
    80→  private final OpenAPI openApi;
    81→
    82→  private MappingContext context;
    83→
    84→  public OntologyMapper(YamlConfig config) {
    85→    this.config = Objects.requireNonNull(config);
    86→    this.manager = OWLManager.createOWLOntologyManager();
    87→    this.ontology = loadOntologies();
    88→    this.openApi = deepCopy(config.getTemplates().getOpenapi(), OpenAPI.class);
    89→  }
    90→
    91→  /**
    92→   * Load ontologies specified in config into manager member
    93→   * <ul>
    94→   *   <li>Merges into a single ontology (saves result as MERGED_FILENAME)</li>
    95→   *    <li>Flattens namespaces according to rules in config (saves result as @see FLATTENED_FILENAME)</li>
    96→   * </ul>
    97→   * on exit manager will be initialized with this ontology
    98→   */
    99→  private OWLOntology loadOntologies() {
   100→    try {
   101→      OWLOntologyManager loadingManager = OWLManager.createOWLOntologyManager();
   102→      if (null != config.getCatalogFile()) {
   103→        try {
   104→          loadingManager.getIRIMappers().add(new XMLCatalogIRIMapper(config.getCatalogFile().toFile()));
   105→        } catch (IOException e) {
   106→          logger.warning("Bad catalog file, ignoring: " + e.getLocalizedMessage());
   107→        }
   108→      }
   109→
   110→      // Load the ontology into the manager
   111→      Map<String, OWLOntology> ontologyByPath = AsgUtils.downloadOntologies(loadingManager, config.getOntologies(),
   112→          config.getApiOutputDir());
   113→
   114→      // merge all ontologies into a single namespace
   115→      final OWLOntologyManager flattenedManager = OWLManager.createOWLOntologyManager();
   116→      final OWLOntology target = new OWLOntologyMerger(loadingManager).createMergedOntology(flattenedManager,
   117→          ontologyByPath.values()
   118→          .stream().findFirst().orElseThrow().getOntologyID().getOntologyIRI().orElseThrow());
   119→
   120→      // Save merged ontologies to a flat ontology file
   121→      Path mergedOntologyPath = config.getApiOutputDir().resolve(MERGED_FILENAME);
   122→      flattenedManager.saveOntology(target, new FileOutputStream(mergedOntologyPath.toFile()));
   123→
   124→      // And reload from there into a new manager (problems with Document IRI unless loaded from file)
   125→      AsgUtils.downloadOntologies(this.manager, List.of(URI.create(mergedOntologyPath.toString())),
   126→          config.getApiOutputDir());
   127→      if (this.manager.ontologies().count() == 1)
   128→        logger.info("Ontologies merged");
   129→      else
   130→        throw new RuntimeException("Single resultant ontology expected");
   131→
   132→      // Apply any namespace mappings in config
   133→      Optional.ofNullable(config.getNamespaceMappings())
   134→          .ifPresent(configMappings -> AsgUtils.applyNamespaceMappings(manager, configMappings));
   135→
   136→      // Save a copy for reference
   137→      OWLOntology result = this.manager.ontologies().findFirst().orElseThrow();
   138→      manager.saveOntology(result, new FileOutputStream(config.getApiOutputDir().resolve(FLATTENED_FILENAME).toFile()));
   139→
   140→      return result;
   141→    } catch (OWLOntologyStorageException | IOException | OWLOntologyCreationException e) {
   142→      throw new RuntimeException("Unable to create flattened/merged ontology", e);
