package com.grl.component.asg;

import com.grl.component.asg.configuration.NamespaceMappingsDeserializer;
import java.io.File;
import java.io.IOException;
import java.io.InputStream;
import java.net.HttpURLConnection;
import java.net.URI;
import java.net.URISyntaxException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.nio.file.StandardCopyOption;
import java.util.Collection;
import java.util.Collections;
import java.util.HashMap;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.Optional;
import java.util.Set;
import java.util.function.Function;
import java.util.logging.Logger;
import java.util.regex.Pattern;
import javax.annotation.Nonnull;
import javax.annotation.Nullable;
import org.apache.commons.lang3.StringUtils;
import org.apache.commons.lang3.tuple.ImmutablePair;
import org.apache.commons.lang3.tuple.Pair;
import org.semanticweb.owlapi.io.FileDocumentSource;
import org.semanticweb.owlapi.model.IRI;
import org.semanticweb.owlapi.model.MissingImportHandlingStrategy;
import org.semanticweb.owlapi.model.OWLEntity;
import org.semanticweb.owlapi.model.OWLOntology;
import org.semanticweb.owlapi.model.OWLOntologyChange;
import org.semanticweb.owlapi.model.OWLOntologyCreationException;
import org.semanticweb.owlapi.model.OWLOntologyLoaderConfiguration;
import org.semanticweb.owlapi.model.OWLOntologyManager;
import org.semanticweb.owlapi.util.OWLEntityURIConverter;
import org.semanticweb.owlapi.util.OWLEntityURIConverterStrategy;

public class AsgUtils {
  private static final Logger logger = Logger.getLogger(AsgUtils.class.getName());

  public static final String[] POSSIBLE_VOCAB_SERIALIZATIONS = {"application/rdf+xml", "text/turtle", "text/n3",
      "application/ld+json"};

  /**
   * Method that will download an ontology given its URI, doing content negotiation The ontology
   * will be downloaded in the first serialization available (see
   * Constants.POSSIBLE_VOCAB_SERIALIZATIONS)
   *
   * @param uri          the URI of the ontology
   * @param downloadPath path where the ontology will be saved locally.
   */
  public static void downloadOntology(URI uri, String downloadPath) {
    for (String serialization : POSSIBLE_VOCAB_SERIALIZATIONS) {
      logger.info("Attempting to download vocabulary in " + serialization);
      try {
        HttpURLConnection connection = (HttpURLConnection) uri.toURL().openConnection();
        connection.setRequestMethod("GET");
        connection.setInstanceFollowRedirects(true);
        connection.setRequestProperty("Accept", serialization);
        int status = connection.getResponseCode();
        boolean redirect = false;
        if (status != HttpURLConnection.HTTP_OK) {
          if (status == HttpURLConnection.HTTP_MOVED_TEMP || status == HttpURLConnection.HTTP_MOVED_PERM || status == HttpURLConnection.HTTP_SEE_OTHER)
            redirect = true;
        }
        // there are some vocabularies with multiple redirections:
        // 301 -> 303 -> owl
        while (redirect) {
          String newUrl = connection.getHeaderField("Location");
          connection = (HttpURLConnection) new URI(newUrl).toURL().openConnection();
          connection.setRequestProperty("Accept", serialization);
          status = connection.getResponseCode();
          if (status != HttpURLConnection.HTTP_MOVED_TEMP && status != HttpURLConnection.HTTP_MOVED_PERM && status != HttpURLConnection.HTTP_SEE_OTHER)
            redirect = false;
        }
        InputStream in = connection.getInputStream();
        Files.copy(in, Paths.get(downloadPath), StandardCopyOption.REPLACE_EXISTING);
        in.close();
        break; // if the vocabulary is downloaded, then we don't download it for the other
        // serializations
      } catch (IOException e) {

        throw new RuntimeException("Failed to download vocabulary in RDF format [" + serialization + "]: ", e);
      } catch (URISyntaxException e) {
        throw new RuntimeException(e);
      }
    }
  }

  /**
   * Given a sample uri return (up to 5) alternatives closely matching it from candidate collection
   *
   * @param sample string that failed some test
   * @param candidates possible candidates that might have been meant
   * @param limit      or null for default 5
   * @return up to limit closest matching candidates
   */
  public static String[] doYouMean(String sample, Collection<String> candidates, @Nullable Integer limit) {
    return candidates.stream()
        .map((candidate) -> ImmutablePair.of(StringUtils.getLevenshteinDistance(candidate, sample), candidate))
        .sorted((p1, p2) -> p1.left - p2.left).limit(Optional.ofNullable(limit).orElse(5)).map(p -> p.right)
        .toArray(String[]::new);

  }

  record InvertablePattern(boolean invert, Pattern pattern) {

    static InvertablePattern fromMapping(String s) {
      return s.length() > 1 && s.startsWith("!") ? new InvertablePattern(true,
          Pattern.compile(s.substring(1))) : new InvertablePattern(false, Pattern.compile(s));
    }

  }

  /**
   * @param manager            container of ontologies to apply mappings to
   * @param configuredMappings map of lists of namespace regexps to be mapped to destination namespace. If destination namespace
   *                           is NamespaceMappingsDeserializer.DEFAULT_KEY it will be replace with the first defined default document base iri
   */
  public static void applyNamespaceMappings(OWLOntologyManager manager,
      Map<String, Set<String>> configuredMappings) {
    Optional<String> defaultIri = manager.ontologies()
        .map(owlOntology -> owlOntology.getOntologyID().getDefaultDocumentIRI())
        .flatMap(Optional::stream).findFirst().map(Objects::toString);
    final OWLEntityURIConverter entityConverter = new OWLEntityURIConverter(manager, manager.ontologies()
        .toList(), new OWLEntityURIConverterStrategy() {
      // Expand map of lists to 1:1 source->dest namespace map for easy lookup
      final List<Pair<InvertablePattern, String>> namespacePatternMappings = Optional.ofNullable(
              configuredMappings)
          .map(mappings -> mappings.entrySet().stream().flatMap(stringListEntry -> stringListEntry.getValue().stream()
                  .map(s -> Pair.of(InvertablePattern.fromMapping(s),
                      stringListEntry.getKey().equals(NamespaceMappingsDeserializer.DEFAULT_NS)
                          ? defaultIri.orElseThrow() : stringListEntry.getKey())))
              .toList())
          .orElse(Collections.emptyList());
      final Map<String, Function<IRI, IRI>> mappedNamespaces = new HashMap<>();

      /**
       * If the entity has an IRI, see if there is a namespace mapping in the config and return mapped version
       * otherwise return unchanged iri (or null)
       * @param owlEntity the entity to convert
       * @return possibly mapped iri
       */
      @Override
      public IRI getConvertedIRI(@Nonnull OWLEntity owlEntity) {
        final IRI entityIRI = owlEntity.getIRI();
        return Optional.of(mappedNamespaces.computeIfAbsent(entityIRI.getNamespace(),
                // Haven't mapped this before - find the first regexp that matches this namespace, if any
                s -> namespacePatternMappings.stream()
                    .filter(patternStringPair -> patternStringPair.getLeft().pattern.asPredicate()
                        .test(s)).findFirst().filter(pair -> !pair.getLeft().invert)
                    .map(pair -> {
                      return (Function<IRI, IRI>) (iri) -> IRI.create(pair.getRight(),
                          iri.getRemainder().orElse(null));
                    })
                    .orElse(Function.identity())))
            .map(mapper -> mapper.apply(entityIRI)).orElse(entityIRI);
      }
    });
    // Commit changes to ontologies
    final List<OWLOntologyChange> changes = entityConverter.getChanges();
    logger.info("Remapped " + changes.size() / 2 + " IRIs");
    manager.applyChanges(changes);
  }

  public static Map<String, OWLOntology> downloadOntologies(OWLOntologyManager manager,
      List<URI> configOntologies,
                                                     Path destinationDir) throws OWLOntologyCreationException {
    if (Objects.requireNonNull(configOntologies).isEmpty())
      throw new RuntimeException("No ontologies specified");
    final LinkedHashMap<String, OWLOntology> ontologyByPath = new LinkedHashMap<>();
    for (int i = 0; i < configOntologies.size(); i++) {
      URI ontologyUri = configOntologies.get(i);
      // copy the ontologies used in the destination folder
      String destinationPath = destinationDir + File.separator + "ontology" + i + ".owl";
      File ontologyFile = new File(destinationPath);
      // content negotiation + download in case a URI is added
      String scheme = ontologyUri.getScheme();
      if ("http".equals(scheme) || "https".equals(scheme)) {
        // download ontology to local path
        downloadOntology(ontologyUri, destinationPath);
      } else if (StringUtils.isEmpty(scheme) || "file".equals(scheme)) {
        try {
          // copy to the right folder
          Files.copy(Path.of(ontologyUri.getSchemeSpecificPart()), ontologyFile.toPath(),
              StandardCopyOption.REPLACE_EXISTING);
        } catch (IOException ex) {
          throw new RuntimeException("ERROR while loading file: " + ontologyUri, ex);
        }
      }

      OWLOntologyLoaderConfiguration loadingConfig = new OWLOntologyLoaderConfiguration();
      loadingConfig = loadingConfig.setMissingImportHandlingStrategy(MissingImportHandlingStrategy.THROW_EXCEPTION)
          .withAllowDuplicatesInConstructSets(true); // required so anonymous classes aren't inlined
      ontologyByPath.put(destinationPath,
          manager.loadOntologyFromOntologyDocument(new FileDocumentSource(new File(destinationPath)), loadingConfig));
    }
    return ontologyByPath;
  }

}

