// File: src/main/java/com/grl/component/asg/configuration/NamespaceMappingsDeserializer.java
package com.grl.component.asg.configuration;

import com.fasterxml.jackson.core.JsonParser;
import com.fasterxml.jackson.databind.DeserializationContext;
import com.fasterxml.jackson.databind.JsonDeserializer;
import com.fasterxml.jackson.databind.JsonNode;
import java.io.IOException;
import java.util.HashMap;
import java.util.HashSet;
import java.util.Iterator;
import java.util.Map;
import java.util.Set;


/**
 * Custom deserializer for namespace mappings. Supports deserialization from either a map format
 * (object with arrays or strings) or a single set format (array of strings). Returns a Map\<String,
 * Set\<String\>\> representing the namespace mappings.
 */
public class NamespaceMappingsDeserializer extends JsonDeserializer<Map<String, Set<String>>> {

  public static final String DEFAULT_NS = "<default>";

  @Override
  public Map<String, Set<String>> deserialize(JsonParser p, DeserializationContext ctxt)
      throws IOException {
    JsonNode node = p.getCodec().readTree(p);
    Map<String, Set<String>> result = new HashMap<>();

    if (node.isObject()) {

      // Map format
      Iterator<Map.Entry<String, JsonNode>> fields = node.fields();
      while (fields.hasNext()) {
        Map.Entry<String, JsonNode> entry = fields.next();
        Set<String> values = new HashSet<>();
        if (entry.getValue().isArray()) {
          for (JsonNode v : entry.getValue()) {
            values.add(v.asText());
          }
        } else {
          values.add(entry.getValue().asText());
        }
        result.put(entry.getKey(), values);
      }
    } else if (node.isArray()) {
      // Single set format
      Set<String> values = new HashSet<>();
      for (JsonNode v : node) {
        values.add(v.asText());
      }
      result.put(DEFAULT_NS, values); // Use a default key or handle as needed
    }
    return result;
  }

  @Override
  public Map<String, Set<String>> deserialize(JsonParser p, DeserializationContext ctxt,
      Map<String, Set<String>> intoMap)
      throws IOException {
    Map<String, Set<String>> result = deserialize(p, ctxt);
    for (Map.Entry<String, Set<String>> entry : result.entrySet()) {
      intoMap.merge(entry.getKey(), entry.getValue(), (oldSet, newSet) -> {
        oldSet.addAll(newSet);
        return oldSet;
      });
    }
    return intoMap;
  }

}

