package com.grl.component.schema;

import java.util.Objects;
import org.semanticweb.owlapi.model.HasIRI;
import org.semanticweb.owlapi.model.IRI;
import org.semanticweb.owlapi.model.OWLClass;
import org.semanticweb.owlapi.model.OWLDataProperty;
import org.semanticweb.owlapi.model.OWLEntity;
import org.semanticweb.owlapi.model.OWLNamedIndividual;
import org.semanticweb.owlapi.model.OWLObjectProperty;
import org.semanticweb.owlapi.util.IRIShortFormProvider;
import org.semanticweb.owlapi.util.SimpleIRIShortFormProvider;

/**
 * Utility class for resolving property names from OWL properties. Provides consistent property name
 * extraction using IRI short forms.
 */
public class PropertyNameResolver {

  private final IRIShortFormProvider shortFormProvider;

  public PropertyNameResolver() {
    this(new SimpleIRIShortFormProvider());
  }

  public PropertyNameResolver(IRIShortFormProvider shortFormProvider) {
    this.shortFormProvider = Objects.requireNonNull(shortFormProvider,
        "shortFormProvider must not be null");
  }

  /**
   * Resolves the short form name of an OWL object property.
   *
   * @param property the OWL object property
   * @return the short form name, never null
   * @throws NullPointerException if property is null
   */
  public String resolve(OWLObjectProperty property) {
    Objects.requireNonNull(property, "property must not be null");
    return resolve(property.getIRI());
  }

  /**
   * Resolves the short form name of an OWL data property.
   *
   * @param property the OWL data property
   * @return the short form name, never null
   * @throws NullPointerException if property is null
   */
  public String resolve(OWLDataProperty property) {
    Objects.requireNonNull(property, "property must not be null");
    return resolve(property.getIRI());
  }

  /**
   * Resolves the short form name of an OWL class.
   *
   * @param owlClass the OWL class
   * @return the short form name, never null
   * @throws NullPointerException if owlClass is null
   */
  public String resolve(OWLClass owlClass) {
    Objects.requireNonNull(owlClass, "owlClass must not be null");
    return resolve(owlClass.getIRI());
  }

  /**
   * Resolves the short form name of an OWL named individual.
   *
   * @param individual the OWL named individual
   * @return the short form name, never null
   * @throws NullPointerException if individual is null
   */
  public String resolve(OWLNamedIndividual individual) {
    Objects.requireNonNull(individual, "individual must not be null");
    return resolve(individual.getIRI());
  }

  /**
   * Resolves the short form name of an OWL entity.
   *
   * @param entity the OWL entity
   * @return the short form name, never null
   * @throws NullPointerException if entity is null
   */
  public String resolve(OWLEntity entity) {
    Objects.requireNonNull(entity, "entity must not be null");
    return resolve(entity.getIRI());
  }

  /**
   * Resolves the short form name of any object with an IRI.
   *
   * @param hasIRI the object with an IRI
   * @return the short form name, never null
   * @throws NullPointerException if hasIRI is null
   */
  public String resolve(HasIRI hasIRI) {
    Objects.requireNonNull(hasIRI, "hasIRI must not be null");
    return resolve(hasIRI.getIRI());
  }

  /**
   * Resolves the short form name of an IRI.
   *
   * @param iri the IRI
   * @return the short form name, never null
   * @throws NullPointerException if iri is null
   */
  public String resolve(IRI iri) {
    Objects.requireNonNull(iri, "iri must not be null");
    String shortForm = shortFormProvider.getShortForm(iri);
    return Objects.requireNonNull(shortForm, "shortForm must not be null");
  }
}

