package com.grl.component.asg;

import com.fasterxml.jackson.annotation.JsonInclude.Include;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.SerializationFeature;
import com.fasterxml.jackson.databind.module.SimpleModule;
import com.grl.component.asg.configuration.Config;
import com.grl.component.asg.configuration.YamlConfig;
import com.grl.component.mapper.OntologyMapper;
import io.swagger.oas.inflector.examples.ExampleBuilder;
import io.swagger.oas.inflector.examples.models.Example;
import io.swagger.oas.inflector.processors.JsonNodeExampleSerializer;
import io.swagger.parser.OpenAPIParser;
import io.swagger.v3.core.util.Json;
import io.swagger.v3.core.util.ObjectMapperFactory;
import io.swagger.v3.core.util.Yaml;
import io.swagger.v3.oas.models.OpenAPI;
import io.swagger.v3.oas.models.PathItem;
import io.swagger.v3.oas.models.security.OAuthFlow;
import io.swagger.v3.oas.models.security.OAuthFlows;
import io.swagger.v3.oas.models.security.Scopes;
import io.swagger.v3.oas.models.security.SecurityScheme;
import io.swagger.v3.parser.core.models.ParseOptions;
import io.swagger.v3.parser.core.models.SwaggerParseResult;
import java.io.File;
import java.io.IOException;
import java.io.InputStream;
import java.net.URI;
import java.nio.file.Path;
import java.util.Collection;
import java.util.List;
import java.util.Objects;
import java.util.Optional;
import java.util.Set;
import java.util.logging.LogManager;
import java.util.logging.Logger;
import java.util.stream.Collectors;
import org.apache.commons.cli.CommandLine;
import org.apache.commons.cli.DefaultParser;
import org.apache.commons.cli.HelpFormatter;
import org.apache.commons.cli.Option;
import org.apache.commons.cli.Options;
import org.apache.commons.cli.ParseException;
import org.apache.commons.lang3.StringUtils;
import org.apache.commons.lang3.tuple.Pair;

public class Asg {

  private static final Logger logger = Logger.getLogger(Asg.class.getName());

  static {
    try {
      InputStream stream = Asg.class.getResourceAsStream("logging.properties");
      LogManager.getLogManager().readConfiguration(stream);
    } catch (Exception e) {
      throw new RuntimeException(e);
    }
    SimpleModule simpleModule = new SimpleModule().addSerializer(new JsonNodeExampleSerializer());
    Json.mapper().registerModule(simpleModule);
  }

  private final YamlConfig config;

  private Asg(YamlConfig config) {
    this.config = Objects.requireNonNull(config);
  }

  void generate() {
    logger.info("Preparing ontology and generating api");
    ensureAPIOutputDirExists();
    saveEffectiveConfig();
    generateOpenApiSpecs(addSecurityScheme(addExamples(OntologyMapper.map(config))));
  }

  void flattenOnly() {
    logger.info("Option --no-generate selected: will output prepared ontology from given config");
    ensureAPIOutputDirExists();
    saveEffectiveConfig();
    new OntologyMapper(config); // loads and outputs ontology
  }

  private void ensureAPIOutputDirExists() {
    Path outputDir = config.getApiOutputDir();
    if (!outputDir.toFile().exists()) {
      boolean mkdirs = outputDir.toFile().mkdirs();
      if (!mkdirs) {
        throw new RuntimeException("Failed to create output directory: " + outputDir);
      }
    }
  }

  private void saveEffectiveConfig() {
    try {
      Yaml.mapper().writeValue(config.getApiOutputDir().resolve("effective-config.yaml").toFile(), config);
    } catch (IOException e) {
      throw new RuntimeException(e);
    }

  }

  public static void main(String[] args) {
    try {
      CommandLine commandLine = parseCommandLine(args);
      YamlConfig config = Config.load(Path.of(commandLine.getOptionValue("config")));

      // if output dir on command line apply to config
      Optional.ofNullable(commandLine.getOptionValue("output-dir"))
          .map(Path::of)
          .map(Path::toAbsolutePath)
          .ifPresent(config::setOutputDir);
      if (commandLine.hasOption("ontology-file")) {
        // ontology provided on command line - override config
        String ontologyFile = commandLine.getOptionValue("ontology-file");
        config.setOntologies(List.of(ontologyFile.matches("^\\w+://") ? new URI(ontologyFile)
            : Path.of(ontologyFile).toAbsolutePath().toUri()));
      }
      // if output dir on command line apply to config
      Optional.ofNullable(commandLine.getOptionValue("output-dir"))
          .map(Path::of)
          .map(Path::toAbsolutePath)
          .ifPresent(config::setOutputDir);

      Asg asg = new Asg(config);
      if (commandLine.hasOption("no-generate")) {
        asg.flattenOnly();
      } else {
        asg.generate();
      }
    } catch (Exception e) {
      logger.severe(e.getMessage());
      throw new RuntimeException(e);
    }
  }

  private static CommandLine parseCommandLine(String[] args) {
    // obtain the options to pass configuration
    Options options = new Options();
    Option config = new Option("c", "config", true, "configuration file path");
    config.setRequired(true);
    options.addOption(config);
    options.addOption(
        new Option("f", "ontology-file", true, "override the ontology file specified in config"));
    options.addOption(
        new Option("o", "output-dir", true, "override the output directpry specified in config"));
    options.addOption(new Option("G", "no-generate", false,
        "stop after loading ontology and output flattened version"));

    try {
      return new DefaultParser().parse(options, args);
    } catch (ParseException e) {
      new HelpFormatter().printHelp("Asg", options);
      throw new RuntimeException(e);
    }

  }

  private OpenAPI addExamples(OpenAPI openApiBase) {
    openApiBase.getPaths().values()
        .forEach(pathItem -> Optional.ofNullable(pathItem.readOperationsMap().get(PathItem.HttpMethod.GET))
            .flatMap(operation -> Optional.ofNullable(operation.getResponses().get("200"))
                .flatMap(apiResponse -> Optional.ofNullable(apiResponse.getContent())
                    .map(content -> content.get("application/json")))).ifPresent(mediaType -> {
              Example example = ExampleBuilder.fromSchema(mediaType.getSchema(), openApiBase.getComponents()
                  .getSchemas());
              mediaType.setExample(Json.mapper().valueToTree(example));
            }));

    return openApiBase;
  }

  /**
   * Generate the security spec for the whole api by gathering all required scopes
   *
   * @param openAPIBase
   * @return
   */
  private OpenAPI addSecurityScheme(OpenAPI openAPIBase) {
    config.getOAuth2SecuritySchemeName().ifPresentOrElse(oauthSchemaName -> {
      Set<String> allScopes = openAPIBase.getPaths().values().stream()
          .flatMap(pathItem -> pathItem.readOperations().stream())
          .flatMap(operation -> Optional.ofNullable(operation.getSecurity()).stream()
              .flatMap(securityRequirements -> securityRequirements.stream()
                  .filter(securityRequirement -> securityRequirement.containsKey(oauthSchemaName))
                  .flatMap(securityRequirement -> securityRequirement.values().stream()))).flatMap(Collection::stream)
          .collect(Collectors.toUnmodifiableSet());

      SecurityScheme securityScheme = Optional.ofNullable(openAPIBase.getComponents().getSecuritySchemes())
          .map(stringSecuritySchemeMap -> stringSecuritySchemeMap.get(oauthSchemaName)).orElseGet(SecurityScheme::new);
      OAuthFlows flows = securityScheme.flows(Optional.ofNullable(securityScheme.getFlows()).orElseGet(OAuthFlows::new))
          .getFlows();
      OAuthFlow flow = flows.authorizationCode(Optional.ofNullable(flows.getAuthorizationCode())
          .orElseGet(OAuthFlow::new)).getAuthorizationCode();
      Scopes scopes = flow.scopes(Optional.ofNullable(flow.getScopes()).orElseGet(Scopes::new)).getScopes();
      allScopes.stream().sorted()
          .forEach(s -> {scopes.put(s, StringUtils.capitalize(StringUtils.replacePattern(s, "\\W", " ")));});
      openAPIBase.schemaRequirement(oauthSchemaName, securityScheme);
    }, () -> {
      logger.warning("No oauth securitySchemeName or oauth securityScheme in template components - auth scopes will " +
          "not be added");
    });
    return openAPIBase;
  }

  private void generateOpenApiSpecs(OpenAPI openApiBase) {
    List.of(Pair.of(ObjectMapperFactory.createYaml31(), "yaml"), Pair.of(ObjectMapperFactory.createJson31(), "json"))
        .forEach(mapperExtension -> {
      ObjectMapper mapper = mapperExtension.getLeft();
          mapper.setSerializationInclusion(Include.NON_NULL);
      mapper.enable(SerializationFeature.INDENT_OUTPUT);
      File outputFile = config.getApiOutputDir().resolve("openapi." + mapperExtension.getRight()).toFile();
      try {
