// File: src/test/java/com/grl/component/asg/AsgUtilsTest.java
package com.grl.component.asg;

import java.util.HashMap;
import java.util.Map;
import java.util.Set;
import org.junit.jupiter.api.Assertions;
import org.junit.jupiter.api.Test;
import org.semanticweb.owlapi.apibinding.OWLManager;
import org.semanticweb.owlapi.model.IRI;
import org.semanticweb.owlapi.model.OWLDataFactory;
import org.semanticweb.owlapi.model.OWLIndividual;
import org.semanticweb.owlapi.model.OWLObjectProperty;
import org.semanticweb.owlapi.model.OWLObjectPropertyAssertionAxiom;
import org.semanticweb.owlapi.model.OWLOntology;
import org.semanticweb.owlapi.model.OWLOntologyCreationException;
import org.semanticweb.owlapi.model.OWLOntologyManager;

class AsgUtilsTest {

  OWLObjectPropertyAssertionAxiom testAxiom(OWLDataFactory factory, String ontologyIRI) {
    OWLIndividual john = factory.getOWLNamedIndividual(IRI
        .create(ontologyIRI + "John"));
    OWLIndividual mary = factory.getOWLNamedIndividual(IRI
        .create(ontologyIRI + "Mary"));
    OWLObjectProperty hasWife = factory.getOWLObjectProperty(IRI
        .create(ontologyIRI + "hasWife"));
    OWLObjectPropertyAssertionAxiom axiom1 = factory
        .getOWLObjectPropertyAssertionAxiom(hasWife, john, mary);
    return axiom1;
  }

  @Test
  void testApplyNamespaceMappings() throws OWLOntologyCreationException {
    OWLOntologyManager manager = OWLManager.createOWLOntologyManager();
    OWLOntology ontology = manager.createOntology();
    OWLDataFactory factory = manager.getOWLDataFactory();
    ontology.add(testAxiom(factory, "http://oldnamespace.com#"));

    // Mapping: regex for oldnamespace -> newnamespace
    Map<String, Set<String>> mappings = new HashMap<>();
    mappings.put("http://newnamespace.com#", Set.of("http://oldnamespace.com#.*"));

    ontology.add(testAxiom(factory, "http://oldnamespace.com#"));

    // Call method

    AsgUtils.applyNamespaceMappings(manager, mappings);

    Assertions.assertTrue(ontology.containsAxiom(testAxiom(factory, "http://newnamespace.com#")));
  }


  @Test
  void testApplyNamespaceMappingsHonoursInvertFlag() throws OWLOntologyCreationException {
    OWLOntologyManager manager = OWLManager.createOWLOntologyManager();
    OWLOntology ontology = manager.createOntology();
    OWLDataFactory factory = manager.getOWLDataFactory();
    ontology.add(testAxiom(factory, "http://oldnamespace.com#"));
    ontology.add(testAxiom(factory, "http://excluded.com#"));

    // Mapping: invert pattern "!http://excluded.com#" should NOT remap this namespace
    Map<String, Set<String>> mappings = new HashMap<>();
    mappings.put("http://newnamespace.com#",
        Set.of("http://oldnamespace.com#", "!http://excluded.com#"));

    AsgUtils.applyNamespaceMappings(manager, mappings);

    Assertions.assertTrue(ontology.containsAxiom(testAxiom(factory, "http://newnamespace.com#")));
    Assertions.assertTrue(ontology.containsAxiom(testAxiom(factory, "http://excluded.com#")));
  }
}

