package com.grl.component.asg.configuration;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.module.SimpleModule;
import java.util.Map;
import java.util.Set;
import org.junit.jupiter.api.Test;

public class NamespaceMappingsDeserializerTest {

  @Test
  public void deserializesMapFormatWithArrays() throws Exception {
    String json = "{ \"ns1\": [\"a\", \"b\"], \"ns2\": [\"c\"] }";
    ObjectMapper mapper = new ObjectMapper();
    SimpleModule module = new SimpleModule();
    module.addDeserializer(Map.class, new NamespaceMappingsDeserializer());
    mapper.registerModule(module);

    @SuppressWarnings("unchecked") Map<String, Set<String>> result = mapper.readValue(json,
        Map.class);
    assertEquals(Set.of("a", "b"), result.get("ns1"));
    assertEquals(Set.of("c"), result.get("ns2"));
  }

  @Test
  public void deserializesMapFormatWithSingleString() throws Exception {
    String json = "{ \"ns1\": \"a\", \"ns2\": \"b\" }";
    ObjectMapper mapper = new ObjectMapper();
    SimpleModule module = new SimpleModule();
    module.addDeserializer(Map.class, new NamespaceMappingsDeserializer());
    mapper.registerModule(module);

    @SuppressWarnings("unchecked") Map<String, Set<String>> result = mapper.readValue(json,
        Map.class);
    assertEquals(Set.of("a"), result.get("ns1"));
    assertEquals(Set.of("b"), result.get("ns2"));
  }

  @Test
  public void deserializesArrayFormat() throws Exception {
    String json = "[\"a\", \"b\", \"c\"]";
    ObjectMapper mapper = new ObjectMapper();
    SimpleModule module = new SimpleModule();
    module.addDeserializer(Map.class, new NamespaceMappingsDeserializer());
    mapper.registerModule(module);

    @SuppressWarnings("unchecked") Map<String, Set<String>> result = mapper.readValue(json,
        Map.class);
    assertEquals(Set.of("a", "b", "c"), result.get(NamespaceMappingsDeserializer.DEFAULT_NS));
    assertEquals(1, result.size());
  }

  @Test
  public void deserializesEmptyArrayFormat() throws Exception {
    String json = "[]";
    ObjectMapper mapper = new ObjectMapper();
    SimpleModule module = new SimpleModule();
    module.addDeserializer(Map.class, new NamespaceMappingsDeserializer());
    mapper.registerModule(module);

    @SuppressWarnings("unchecked") Map<String, Set<String>> result = mapper.readValue(json,
        Map.class);
    assertTrue(result.containsKey(NamespaceMappingsDeserializer.DEFAULT_NS));
    assertTrue(result.get(NamespaceMappingsDeserializer.DEFAULT_NS).isEmpty());
  }

  @Test
  public void deserializesEmptyObjectFormat() throws Exception {
    String json = "{}";
    ObjectMapper mapper = new ObjectMapper();
    SimpleModule module = new SimpleModule();
    module.addDeserializer(Map.class, new NamespaceMappingsDeserializer());
    mapper.registerModule(module);

    Map result = mapper.readValue(json, Map.class);
    assertTrue(result.isEmpty());
  }
}

