package regression;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import com.grl.TestUtil;
import com.jayway.jsonpath.ReadContext;
import java.util.List;
import java.util.Map;
import java.util.Set;
import org.junit.jupiter.api.Test;


/**
 * Test that a simple API (employer) gets generated correctly.
 *
 * <ul>
 *  <li>Api has title, description, termsOfService, contact, version, x-grl-api-label, x-grl-graph-namespace in info.</li>
 *  <li>Api has Employee and Employer resources.</li>
 *  <li>each resource has single and collection endpoints.</li>
 *  <li>each endpoint has standard methods.</li>
 *  <li>each method has standard parameters and responses.</li>
 *  <li>resources have basic properties only.</li>
 * </ul>
 */
public class SimpleApiIT {

  ReadContext employeeSpec = TestUtil.getGeneratedSpec(
      TestUtil.asFilePath(SimpleApiIT.class, "config_employee.yaml"));

  @Test
  public void withEmployeeInfoIsCorrect() {
    assertEquals("EmploymentAPIV1.0.1", employeeSpec.read("$.info.title"));
    assertEquals("Minimal Test API", employeeSpec.read("$.info.description"));
    assertEquals("some terms", employeeSpec.read("$.info.termsOfService"));
    assertEquals("Test Contact", employeeSpec.read("$.info.contact.name"));
    assertEquals("http://test/url", employeeSpec.read("$.info.contact.url"));
    assertEquals("support@graphresearchlabs.com", employeeSpec.read("$.info.contact.email"));
    assertEquals("1.0.0", employeeSpec.read("$.info.version"));
    assertEquals("EmploymentAPIV1.0.1", employeeSpec.read("$.info.x-grl-api-label"));
    assertEquals("https://www.graphresearchlabs.com/employment/",
        employeeSpec.read("$.info.x-grl-graph-namespace"));
  }

  @Test
  public void withEmployeeTagsCorrect() {
    assertEquals(2, (int) employeeSpec.read("$.tags.length()"));
    assertEquals("Employee", employeeSpec.read("$.tags[0].name"));
    assertEquals("A person who is employed by another person or organizational entity.",
        employeeSpec.read("$.tags[0].description"));
    assertEquals("Employer", employeeSpec.read("$.tags[1].name"));
  }

  @Test
  public void withEmployeePathsCorrect() {
    assertEquals(4, (int) employeeSpec.read("$.paths.length()"));
    assertEquals(
        Set.of("/Employee/{EmployeeId}", "/Employee", "/Employer/{EmployerId}", "/Employer"),
        employeeSpec.read("$.paths.keys()"));
    assertEquals(Set.of("summary", "description", "get", "put", "patch", "delete"),
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].keys()"));
    assertEquals(Set.of("summary", "description", "get", "post"),
        employeeSpec.read("$.paths['/Employee'].keys()"));
  }

  @Test
  public void withEmployeeSingleGetCorrect() {
    assertEquals(List.of("Employee"),
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].get.tags"));
    assertEquals("Employee/single/GET",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].get.operationId"));
    assertEquals(1,
        (int) employeeSpec.read("$.paths['/Employee/{EmployeeId}'].get.parameters.length()"));
    assertEquals("EmployeeId",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].get.parameters[0].name"));
    assertEquals("path",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].get.parameters[0].in"));
    assertTrue(employeeSpec.read("$.paths['/Employee/{EmployeeId}'].get.parameters[0].required",
        Boolean.class));
    assertEquals("string",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].get.parameters[0].schema.type"));
    assertEquals(Set.of("401", "403", "404", "406", "429", "500", "200"),
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].get.responses.keys()"));
    assertEquals("Existing Employee",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].get.responses['200'].description"));
    assertEquals("#/components/schemas/Employee", employeeSpec.read(
        "$.paths['/Employee/{EmployeeId}'].get.responses['200'].content['application/json'].schema['$ref']"));
  }

  @Test
  public void withEmployeeSinglePutCorrect() {
    assertEquals(List.of("Employee"),
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].put.tags"));
    assertEquals("Employee/single/PUT",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].put.operationId"));
    assertEquals(1,
        (int) employeeSpec.read("$.paths['/Employee/{EmployeeId}'].put.parameters.length()"));
    assertEquals("EmployeeId",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].put.parameters[0].name"));
    assertEquals("path",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].put.parameters[0].in"));
    assertTrue(employeeSpec.read("$.paths['/Employee/{EmployeeId}'].put.parameters[0].required",
        Boolean.class));
    assertEquals("string",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].put.parameters[0].schema.type"));
    assertEquals("#/components/schemas/Employee", employeeSpec.read(
        "$.paths['/Employee/{EmployeeId}'].put.requestBody.content['application/json'].schema['$ref']"));
    assertEquals(Set.of("400", "401", "403", "404", "406", "429", "500", "200"),
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].put.responses.keys()"));
    assertEquals("Existing Employee",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].put.responses['200'].description"));
    assertEquals("#/components/schemas/Employee", employeeSpec.read(
        "$.paths['/Employee/{EmployeeId}'].put.responses['200'].content['application/json'].schema['$ref']"));
  }

  @Test
  public void withEmployeeSinglePatchCorrect() {
    assertEquals(List.of("Employee"),
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].patch.tags"));
    assertEquals("Employee/single/PATCH",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].patch.operationId"));
    assertEquals(1,
        (int) employeeSpec.read("$.paths['/Employee/{EmployeeId}'].patch.parameters.length()"));
    assertEquals("EmployeeId",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].patch.parameters[0].name"));
    assertEquals("path",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].patch.parameters[0].in"));
    assertTrue(employeeSpec.read("$.paths['/Employee/{EmployeeId}'].patch.parameters[0].required",
        Boolean.class));
    assertEquals("string",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].patch.parameters[0].schema.type"));
    assertEquals("#/components/schemas/Employee", employeeSpec.read(
        "$.paths['/Employee/{EmployeeId}'].patch.requestBody.content['application/json'].schema['$ref']"));
    assertEquals(Set.of("400", "401", "403", "404", "406", "429", "500", "200"),
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].patch.responses.keys()"));
    assertEquals("Existing Employee",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].patch.responses['200'].description"));
    assertEquals("#/components/schemas/Employee", employeeSpec.read(
        "$.paths['/Employee/{EmployeeId}'].patch.responses['200'].content['application/json'].schema['$ref']"));

  }

  @Test
  public void withEmployeeSingleDeleteCorrect() {
    assertEquals(List.of("Employee"),
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].delete.tags"));
    assertEquals("Employee/single/DELETE",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].delete.operationId"));
    assertEquals(1,
        (int) employeeSpec.read("$.paths['/Employee/{EmployeeId}'].delete.parameters.length()"));
    assertEquals("EmployeeId",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].delete.parameters[0].name"));
    assertEquals("path",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].delete.parameters[0].in"));
    assertTrue(employeeSpec.read("$.paths['/Employee/{EmployeeId}'].delete.parameters[0].required",
        Boolean.class));
    assertEquals("string",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].delete.parameters[0].schema.type"));
    assertEquals(Set.of("401", "403", "404", "406", "429", "500", "200"),
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].delete.responses.keys()"));
    assertEquals("Existing Employee",
        employeeSpec.read("$.paths['/Employee/{EmployeeId}'].delete.responses['200'].description"));
    assertEquals("#/components/schemas/Employee", employeeSpec.read(
        "$.paths['/Employee/{EmployeeId}'].delete.responses['200'].content['application/json'].schema['$ref']"));

  }


  @Test
  public void withEmployeeCollectionGetCorrect() {
    assertEquals(List.of("Employee"), employeeSpec.read("$.paths['/Employee'].get.tags"));
    assertEquals("Employee/collection/GET",
        employeeSpec.read("$.paths['/Employee'].get.operationId"));
    assertEquals(2,
        employeeSpec.read("$.paths['/Employee'].get.parameters.length()", Integer.class));
    Map start = (Map) employeeSpec.read("$.paths['/Employee'].get.parameters[?(@.name=='start')]",
        List.class).getFirst();
    assertEquals("Index of start item", start.get("description"));
    assertEquals("query", start.get("in"));
    Map limit = (Map) employeeSpec.read("$.paths['/Employee'].get.parameters[?(@.name=='limit')]",
        List.class).getFirst();
    assertEquals("Maximum items to return", limit.get("description"));
    assertEquals("query", limit.get("in"));

    assertEquals(Set.of("400", "401", "403", "406", "429", "500", "200"),
        employeeSpec.read("$.paths['/Employee'].get.responses.keys()"));
    assertEquals("Employee Collection",
        employeeSpec.read("$.paths['/Employee'].get.responses['200'].description"));
    assertEquals("#/components/schemas/Employee", employeeSpec.read(
        "$.paths['/Employee'].get.responses['200'].content['application/json'].schema.properties.items.items['$ref']"));
  }

  @Test
  public void withEmployeeCollectionPostCorrect() {
    assertEquals(List.of("Employee"), employeeSpec.read("$.paths['/Employee'].post.tags"));
    assertEquals("Employee/collection/POST",
        employeeSpec.read("$.paths['/Employee'].post.operationId"));
    assertEquals("#/components/schemas/Employee", employeeSpec.read(
        "$.paths['/Employee'].post.requestBody.content['application/json'].schema['$ref']"));
    assertEquals(Set.of("400", "401", "403", "406", "429", "500", "201"),
        employeeSpec.read("$.paths['/Employee'].post.responses.keys()"));
    assertEquals("New Employee",
        employeeSpec.read("$.paths['/Employee'].post.responses['201'].description"));
    assertEquals("#/components/schemas/Employee", employeeSpec.read(
        "$.paths['/Employee'].post.responses['201'].content['application/json'].schema['$ref']"));
  }

  @Test
  public void withEmployeeTestSchema() {
    assertEquals(Set.of("apiID", "name"),
        employeeSpec.read("$.components.schemas.Employee.properties.keys()"));
    assertEquals(List.of("apiID", "name"),
        employeeSpec.read("$.components.schemas.Employee.required"));
    assertEquals("Employee", employeeSpec.read("$.components.schemas.Employee.title"));
    assertEquals(false, employeeSpec.read("$.components.schemas.Employee.additionalProperties",
        Boolean.class));
    assertEquals("A person who is employed by another person or organizational entity.",
        employeeSpec.read("$.components.schemas.Employee.description"));

    assertEquals(1, employeeSpec.read(
        "$.components.schemas.Employee.properties.apiID[?(@.title=='Api Id' && @.type == 'string' && @.description == 'REST ID of the object.' && @.example == 'apiID string value' )]",
        List.class).size());
    assertEquals(1, employeeSpec.read(
        "$.components.schemas.Employer.properties.isConnectedTo[?(@.title=='Is Connected To' && @.type == 'array' && @.items['$ref']== '#/components/schemas/Company')]",
        List.class).size());
  }
}

