package com.grl.component.mapper;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertNull;
import static org.junit.jupiter.api.Assertions.assertSame;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

import com.grl.component.asg.configuration.YamlConfig;
import io.swagger.v3.oas.models.media.Schema;
import java.nio.file.Path;
import java.util.Collections;
import java.util.Set;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.semanticweb.owlapi.apibinding.OWLManager;
import org.semanticweb.owlapi.model.IRI;
import org.semanticweb.owlapi.model.OWLClass;
import org.semanticweb.owlapi.model.OWLDataFactory;
import org.semanticweb.owlapi.model.OWLOntology;
import org.semanticweb.owlapi.model.OWLOntologyCreationException;
import org.semanticweb.owlapi.model.OWLOntologyManager;

class MappingContextTest {

  private static final String TEST_NS = "http://example.org/test#";

  private OWLDataFactory df;
  private OWLOntologyManager manager;
  private OWLOntology ontology;
  private YamlConfig config;
  private OWLClass apiRootClass;
  private OWLClass resourceClass;

  @BeforeEach
  void setUp() throws OWLOntologyCreationException {
    manager = OWLManager.createOWLOntologyManager();
    df = manager.getOWLDataFactory();
    ontology = manager.createOntology(IRI.create(TEST_NS));

    config = new YamlConfig();
    config.setName("TestAPI");
    config.setOutputDir(Path.of("/output"));

    apiRootClass = df.getOWLClass(IRI.create(TEST_NS, "TestAPIRoot"));
    resourceClass = df.getOWLClass(IRI.create(TEST_NS, "TestResource"));
  }

  @Nested
  class ConstructorAndInitialization {

    @Test
    void testAllConstructorParametersStoredCorrectly() {
      Set<OWLClass> resourceClasses = Set.of(resourceClass);

      MappingContext context = new MappingContext(
          TEST_NS,
          ontology,
          "SchemaLabel",
          apiRootClass,
          resourceClasses,
          config
      );

      assertEquals(TEST_NS, context.getDefaultOntologyPrefixIRI());
      assertSame(ontology, context.getOntology());
      assertEquals("SchemaLabel", context.getSchemaLabel());
      assertSame(apiRootClass, context.getApiRootClass());
      assertSame(config, context.getConfig());
    }

    @Test
    void testResourceClassesIsUnmodifiable() {
      Set<OWLClass> resourceClasses = Set.of(resourceClass);

      MappingContext context = new MappingContext(
          TEST_NS, ontology, "SchemaLabel", apiRootClass, resourceClasses, config);

      Set<OWLClass> returnedClasses = context.getResourceClasses();
      assertThrows(UnsupportedOperationException.class, () ->
          returnedClasses.add(df.getOWLClass(IRI.create(TEST_NS, "AnotherClass"))));
    }

    @Test
    void testSchemaCacheInitiallyEmpty() {
      MappingContext context = new MappingContext(
          TEST_NS, ontology, "SchemaLabel", apiRootClass,
          Set.of(resourceClass), config);

      assertTrue(context.getSchemaByRef().isEmpty());
    }

    @Test
    void testManagerInstanceCreated() {
      MappingContext context = new MappingContext(
          TEST_NS, ontology, "SchemaLabel", apiRootClass,
          Set.of(resourceClass), config);

      assertNotNull(context.getManager());
    }
  }

  @Nested
  class SchemaCaching {

    @Test
    void testAddSchemaCreatesAndCachesSchema() throws OWLOntologyCreationException {
      // Create a simple ontology with a class that can be mapped
      OWLOntologyManager testManager = OWLManager.createOWLOntologyManager();
      OWLDataFactory testDf = testManager.getOWLDataFactory();
      OWLOntology testOntology = testManager.createOntology(IRI.create(TEST_NS));

      // Add a class declaration
      OWLClass testClass = testDf.getOWLClass(IRI.create(TEST_NS + "SimpleClass"));
      testManager.addAxiom(testOntology, testDf.getOWLDeclarationAxiom(testClass));

      MappingContext context = new MappingContext(
          TEST_NS, testOntology, "SchemaLabel", apiRootClass,
          Collections.emptySet(), config);

      context.addSchema("SimpleClass");

      assertFalse(context.getSchemaByRef().isEmpty());
      assertTrue(context.getSchemaByRef().containsKey("SimpleClass"));
    }

    @Test
    void testSecondCallReturnsCachedSchema() throws OWLOntologyCreationException {
      OWLOntologyManager testManager = OWLManager.createOWLOntologyManager();
      OWLDataFactory testDf = testManager.getOWLDataFactory();
      OWLOntology testOntology = testManager.createOntology(IRI.create(TEST_NS));

      OWLClass testClass = testDf.getOWLClass(IRI.create(TEST_NS + "CachedClass"));
      testManager.addAxiom(testOntology, testDf.getOWLDeclarationAxiom(testClass));

      MappingContext context = new MappingContext(
          TEST_NS, testOntology, "SchemaLabel", apiRootClass,
          Collections.emptySet(), config);

      // First call
      context.addSchema("CachedClass");
      Schema<?> firstSchema = context.getSchemaByRef().get("CachedClass");

      // Second call
      context.addSchema("CachedClass");
      Schema<?> secondSchema = context.getSchemaByRef().get("CachedClass");

      assertSame(firstSchema, secondSchema, "Should return same cached instance");
    }

    @Test
    void testMultipleDifferentSchemasCachedCorrectly() throws OWLOntologyCreationException {
      OWLOntologyManager testManager = OWLManager.createOWLOntologyManager();
      OWLDataFactory testDf = testManager.getOWLDataFactory();
      OWLOntology testOntology = testManager.createOntology(IRI.create(TEST_NS));

      OWLClass class1 = testDf.getOWLClass(IRI.create(TEST_NS + "Class1"));
      OWLClass class2 = testDf.getOWLClass(IRI.create(TEST_NS + "Class2"));
      testManager.addAxiom(testOntology, testDf.getOWLDeclarationAxiom(class1));
      testManager.addAxiom(testOntology, testDf.getOWLDeclarationAxiom(class2));

      MappingContext context = new MappingContext(
          TEST_NS, testOntology, "SchemaLabel", apiRootClass,
          Collections.emptySet(), config);

      context.addSchema("Class1");
      context.addSchema("Class2");

      assertEquals(2, context.getSchemaByRef().size());
      assertTrue(context.getSchemaByRef().containsKey("Class1"));
      assertTrue(context.getSchemaByRef().containsKey("Class2"));
    }

    @Test
    void testGetSchemaByRefReturnsTheCacheMap() {
      MappingContext context = new MappingContext(
          TEST_NS, ontology, "SchemaLabel", apiRootClass,
          Set.of(resourceClass), config);

      assertNotNull(context.getSchemaByRef());
      // Verify it's the same map instance on repeated calls
      assertSame(context.getSchemaByRef(), context.getSchemaByRef());
    }
  }

  @Nested
  class Getters {

    @Test
