    void testEmptyResourceClassesSet() {
      MappingContext context = new MappingContext(
          ontology, "SchemaLabel", apiRootClass,
          Collections.emptySet(), config);

      assertTrue(context.getResourceClasses().isEmpty());
    }

    @Test
    void testMultipleResourceClasses() {
      OWLClass resource1 = df.getOWLClass(IRI.create(TEST_NS, "Resource1"));
      OWLClass resource2 = df.getOWLClass(IRI.create(TEST_NS, "Resource2"));
      OWLClass resource3 = df.getOWLClass(IRI.create(TEST_NS, "Resource3"));

      MappingContext context = new MappingContext(
