      assertTrue(context.getResourceClasses().contains(resource1));
      assertTrue(context.getResourceClasses().contains(resource2));
      assertTrue(context.getResourceClasses().contains(resource3));
    }
  }

  @Nested
  class ConfigAccess {

    @Test
    void testConfigEnforceRequirednessAccessible() {
      config.setEnforceRequiredness(true);

      MappingContext context = new MappingContext(
          ontology, "SchemaLabel", apiRootClass,
          Set.of(resourceClass), config);

      assertTrue(context.getConfig().isEnforceRequiredness());
    }

    @Test
    void testConfigNameAccessible() {
      config.setName("MyApiName");

      MappingContext context = new MappingContext(
          ontology, "SchemaLabel", apiRootClass,
          Set.of(resourceClass), config);

      assertEquals("MyApiName", context.getConfig().getName());
    }
  }
}

