  private Stream<SecurityRequirement> mapToSecurityItems(String name, PathItem.HttpMethod method,
                                                         Set<String> security) {
    // If apiKey is enabled, add this as a requirement
    Stream.Builder<SecurityRequirement> requirements = Stream.builder();
    config.getApiKeySecuritySchemaName()
        .ifPresent(s -> requirements.add(new SecurityRequirement().addList(s)));

    // oauth2 scheme - add requirment groups for these
    config.getOAuth2SecuritySchemeName().ifPresent(oauthSchemeName -> {
      String template =
          security.isEmpty() ? config.getDefaultSecurityTemplate() : config.getSecurityTemplate();
      if (StringUtils.isEmpty(template)) {
        // no scoped requirements, auth alone is sufficient
        requirements.add(new SecurityRequirement().addList(oauthSchemeName));
      } else {
        // Map scoped requirements
        Map<String, String> replacements = Map.of("api", config.getName(), // name of api
            "action", config.getSecurityActionMappings()
                .getOrDefault(method, ""), // action, mapped from path's http method,
            "model", name // current path's model/resource
        );
        List<String> securityRequirements =
            Stream.of(security, // multiple security names maye be provided
                    List.of("") // non if default
                ).flatMap(Collection::stream)
                .map(s -> new StringSubstitutor(
                    key -> key.equals("security") ? s : replacements.getOrDefault(key, ""), "{",
                    "}", '\'').setEnableSubstitutionInVariables(
                        true) // security annotations can contain replacements
                    .replace(template)).filter(requirement -> {
                  boolean valid = OAUTH_SCOPE_PATTERN.matcher(requirement).matches();
                  if (!valid) {
                    logger.warning(String.format(
                        "%s (%s) security requirement generated ignored (must match " + "https" +
                            "://datatracker.ietf.org/doc/html/rfc6749#section-3.3 scope_token): %s",
                        name, method, requirement));
                  }
                  return valid;
                }).toList();
        securityRequirements.stream().map(
            securityRequirement -> new SecurityRequirement().addList(oauthSchemeName,
                securityRequirement)).forEach(requirements::add);
      }
    });
    return requirements.build();
  }

  private void mapToComponentSchemas(OWLClass resourceClass, String name, String definition) {

    ResourceSchemaMapper schemaMapper = new ResourceSchemaMapper(context, resourceClass, definition);
    Map<String, Schema> schemas = openApi.getComponents()
        .schemas(Optional.ofNullable(openApi.getComponents().getSchemas()).orElse(new LinkedHashMap<>())).getSchemas();
    schemas.put(name, schemaMapper.getSchema());
    schemas.putAll(context.getSchemaByRef());
  }

  private static <T> T deepCopy(T src, Class<T> cls) {
    ObjectMapper mapper = Json.mapper().setSerializationInclusion(Include.NON_NULL);
    try {
      return mapper.readValue(mapper.writeValueAsString(src), cls);
    } catch (JsonProcessingException e) {
      throw new RuntimeException(e);
    }
  }
}

