package com.grl.component.asg.configuration;

import com.fasterxml.jackson.annotation.JsonInclude.Include;
import com.fasterxml.jackson.annotation.JsonMerge;
import com.fasterxml.jackson.core.JacksonException;
import com.fasterxml.jackson.core.JsonParser;
import com.fasterxml.jackson.databind.DeserializationContext;
import com.fasterxml.jackson.databind.DeserializationFeature;
import com.fasterxml.jackson.databind.JsonDeserializer;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.module.SimpleModule;
import com.grl.component.asg.AsgUtils;
import io.swagger.v3.core.util.Yaml;
import io.swagger.v3.oas.models.Components;
import io.swagger.v3.oas.models.OpenAPI;
import io.swagger.v3.oas.models.info.Info;
import io.swagger.v3.oas.models.security.SecurityRequirement;
import jakarta.validation.ConstraintViolation;
import jakarta.validation.ConstraintViolationException;
import jakarta.validation.Validation;
import jakarta.validation.Validator;
import java.io.IOException;
import java.net.URI;
import java.net.URISyntaxException;
import java.net.URLDecoder;
import java.nio.charset.Charset;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.Set;
import java.util.logging.Logger;
import org.apache.commons.lang3.StringUtils;
import org.apache.commons.text.StringSubstitutor;

public class Config {

  private final static Logger logger = Logger.getLogger(Config.class.getName());
  private static final String BOILERPLATE_CONFIG = "/default.config.yaml";
  static final private ObjectMapper yamlMapper = Yaml.mapper()
      .setSerializationInclusion(Include.NON_NULL)
      .enable(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES)
      .addMixIn(OpenAPI.class, MergableOpenApi.class);
  static final private Validator validator = Validation.buildDefaultValidatorFactory()
      .getValidator();

  public static YamlConfig loadInternal(Path configPath) throws IOException {

    // Set up custom deserializer for Path and URI objects relative paths are resolved against the config file's
    // location
    ObjectMapper configMapper = yamlMapper.copy()
        .registerModule(new SimpleModule().addDeserializer(Path.class, new JsonDeserializer<Path>() {
          @Override
          public Path deserialize(JsonParser jsonParser, DeserializationContext deserializationContext) throws IOException, JacksonException {
            Path deserialized = yamlMapper.readValue(jsonParser, Path.class); // call default deserializer
            return deserialized.isAbsolute() ? deserialized : configPath.getParent().resolve(deserialized).normalize();
          }
        }).addDeserializer(URI.class, new JsonDeserializer<URI>() {
          @Override
          public URI deserialize(JsonParser jsonParser, DeserializationContext ctxt) throws IOException,
              JacksonException {
            try {
              // Note urldecode here as the URI ctor urlencodes and we risk a double encode if its stored urlencoded (which is traditional)
              String deserializedAsString = URLDecoder.decode(
                  yamlMapper.readValue(jsonParser, String.class),
                  Charset.defaultCharset());
              URI deserialized = new URI(null, deserializedAsString, null);
              return StringUtils.isEmpty(deserialized.getScheme()) || "file".equals(deserialized.getScheme()) ?
                  configPath.getParent()
                  .resolve(deserialized.getSchemeSpecificPart()).normalize().toUri() : deserialized;
            } catch (URISyntaxException e) {
              throw new RuntimeException(e);
            }
          }
        }));
    // Crudely fix up 'variables' so we have use (e.g. ${configDir}) in the whole string content of the input file
    Map<String, String> variables = Map.of("configDir", configPath.getParent().toAbsolutePath().toString());
    String configAsString = new StringSubstitutor(variables).replace(Files.readString(configPath));
    YamlConfig preParsedConfig = Optional.ofNullable(configMapper.readValue(configAsString, YamlConfig.class))
        .orElseThrow();

    YamlConfig extended = Optional.ofNullable(preParsedConfig.getExtends()).map(extendsConfig -> {
      try {
        return loadInternal(extendsConfig);
      } catch (IOException e) {
        throw new RuntimeException("Failed to read extended config file: " + extendsConfig, e);
      }
    }).orElse(configMapper.readValue(AsgUtils.class.getResourceAsStream(BOILERPLATE_CONFIG), YamlConfig.class));

    // Read config again, merging over default boilerplate
    return Optional.ofNullable(configMapper.readerForUpdating(extended).readValue(configAsString, YamlConfig.class))
        .orElseThrow(() -> new RuntimeException("Config file is empty:" + configPath));
  }

  public static YamlConfig load(Path configPath) throws IOException {
    YamlConfig config = loadInternal(configPath);
    Set<ConstraintViolation<YamlConfig>> violations = validator.validate(config);
    if (!violations.isEmpty()) {
      violations.forEach(violation -> logger.severe(violation.getMessage() + ": " + violation.getInvalidValue()));
      throw new ConstraintViolationException("Config file is invalid: ", violations);
    } else {
      return config;
    }
  }

  /**
   * Hacky interface to supply override annotations to Swagger-defined OpenAPI so we can easily merge properties
   * between configs
   */
  interface MergableOpenApi {
    @JsonMerge
    Components getComponents();

    @JsonMerge
    Info getInfo();

    @JsonMerge
    io.swagger.v3.oas.models.Paths getPaths(); // this doesn't seem to work for Map-based property, though not needed at present, may be fixed by https://github.com/FasterXML/jackson-databind/issues/4922

    @JsonMerge
    List<SecurityRequirement> getSecurity();
  }

}

