   143→    OWLClass apiRootOWLClass = ontology.getClassesInSignature().stream()
   144→        .filter(cls -> nameResolver.resolve(cls).equals(OntologyConstants.apiRoot))
   145→        .findFirst()
   146→        .orElseThrow(() -> new RuntimeException("No APIRoot class found in ontology"));
   147→
   148→    // List of classes marked with APIRoot subclass
   149→    Set<OWLClass> apiRootClasses = ontology.getSubClassAxiomsForSubClass(apiRootOWLClass).stream()
   150→        .map(OWLSubClassOfAxiom::getSuperClass).flatMap(Narrow.to(OWLQuantifiedObjectRestriction.class))
   151→        .filter(objectRestriction -> nameResolver.resolve(
   152→                objectRestriction.getProperty().asOWLObjectProperty())
   153→            .equals(OntologyConstants.hasAPI)).map(objectRestriction -> objectRestriction.getFiller().asOWLClass())
   154→        .collect(Collectors.toSet());
   155→
   156→    // Find intended root class...
   157→    OWLClass apiRootClass = config.getRootClass() != null ?
   158→        // It is specified in config, but must be marked with ApiRoot
   159→        apiRootClasses.stream().filter(WithIRI.of(IRI.create(config.getRootClass()).getShortForm())).findFirst()
   160→            .orElseThrow(() -> new RuntimeException("Not related to APIRoot: " + config.getRootClass()))
   161→        // otherwise if there's a single APIRoot assume that
   162→        : apiRootClasses.stream().reduce((a, b) -> {
   163→      throw new RuntimeException("No valid rootClass defined in config, and cannot infer from APIRoot class " +
   164→          "which has multiple API subclasses. Set rootClass to one of:\n" + String.join("\n", apiRootClasses.stream()
   165→          .map(OWLClass::getIRI).toList()));
   166→
   167→    }).orElseThrow(() -> new RuntimeException("Unable to ascertain root class for API"));
   168→
   169→    // This will be used to match all objects/properties in the schema with annotations
   170→    String schemaLabel = nameResolver.resolve(apiRootClass);
   171→    logger.info("API will be inferred from items annotated with apiLabel of " + schemaLabel);
   172→
   173→    // Set the overall api title
   174→    Info info = Optional.ofNullable(openApi.getInfo()).orElse(new Info());
   175→    info.setTitle(OntologyUtil.getTitle(apiRootClass, ontology));
   176→
   177→    // Save this value as extension for Graph tool usage whan filtering for API-specific data
   178→    info.addExtension(OpenApiConstants.X_GRL_API_LABEL, schemaLabel);
   179→
   180→    // Add extension for ontology namespace
   181→    ontology.getOntologyID().getOntologyIRI()
   182→        .ifPresent(iri -> info.addExtension(OpenApiConstants.X_GRL_GRAPH_NAMESPACE, iri.toString()));
   183→
   184→    openApi.info(info);
