    63→   */
    64→  public void addSchema(OWLClass cls) {
    65→    String shortName = nameResolver.resolve(cls);
    66→    schemaByRef.computeIfAbsent(shortName, s -> {
    67→      if (!computing.contains(s)) {
    68→        computing.add(s);
    69→        try {
    70→          String description = OntologyUtil.getDescription(cls, ontology);
    71→          ResourceSchemaMapper resourceSchemaMapper = new ResourceSchemaMapper(this, cls, description);
    72→          return resourceSchemaMapper.getSchema();
    73→        } finally {
    74→          computing.remove(s);
    75→        }
    76→      } else
    77→        return null; // already being computed, ignore to avoid infinite recursion
    78→    });
    79→  }
